return items.map((item) => {
  const body = item.json.body || item.json;
  return { json: {
    ...body,
    body,
    id: body.id || $execution.id,
    type: body.type || 'workflow_request',
    category: body.category || body.workflow_category || 'contact',
    priority: body.priority || 'normal',
    requester: body.requester || 'openclaw',
    timestamp: body.timestamp || new Date().toISOString(),
    version: body.version || '1.0',
    n8n_owns_execution: true,
    openclaw_external_access: false
  }};
});

const allowedTypes = ['workflow_request','communication_request','context_request','memory_update','handoff','human_intervention'];
const allowedCategories = ['contact','lead','research','helpdesk','marketing','health','communication','memory','escalation','infrastructure'];
return items.map((item) => {
  const j = item.json;
  const valid = allowedTypes.includes(j.type) && allowedCategories.includes(j.category) && j.version === '1.0';
  return { json: { ...j, candidate_valid: valid, validation_errors: valid ? [] : ['request candidate does not match OpenClaw->n8n P2 contract'] } };
});

return items.map((item) => {
  const response = item.json;
  return { json: { ...response, handled_by: 'n8n', response_received_at: new Date().toISOString(), next_request_type: response.type || response.request_candidate?.type || 'communication_request' } };
});

